using System;

public struct Point
{
    public int X { get; }
    public int Y { get; }

    public Point(int x, int y) => (X, Y) = (x, y);

    public static Point operator +(Point a, Point b)
        => new Point(a.X + b.X, a.Y + b.Y);

    public override string ToString() => $"({X}, {Y})";
}

class Program
{
    static void Main()
    {
        Point p1 = new(3, 4);
        Point p2 = new(1, 2);
        Point sum = p1 + p2;
        Console.WriteLine($"{p1} + {p2} = {sum}");
    }
}
